package com.example.auth

import android.content.Context
import android.content.SharedPreferences
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey

class AuthenticationManager(private val context: Context) {
    
    private val masterKey: MasterKey by lazy {
        MasterKey.Builder(context)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()
    }
    
    private val encryptedPrefs: SharedPreferences by lazy {
        EncryptedSharedPreferences.create(
            context,
            PREFS_NAME,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }
    
    fun saveAuthToken(token: String) {
        encryptedPrefs.edit().putString(KEY_AUTH_TOKEN, token).apply()
    }
    
    fun saveUserId(userId: String) {
        encryptedPrefs.edit().putString(KEY_USER_ID, userId).apply()
    }
    
    fun saveAuthData(token: String, userId: String) {
        encryptedPrefs.edit().apply {
            putString(KEY_AUTH_TOKEN, token)
            putString(KEY_USER_ID, userId)
            putBoolean(KEY_IS_LOGGED_IN, true)
            putLong(KEY_LOGIN_TIMESTAMP, System.currentTimeMillis())
        }.apply()
    }
    
    fun getAuthToken(): String? {
        return encryptedPrefs.getString(KEY_AUTH_TOKEN, null)
    }
    
    fun getUserId(): String? {
        return encryptedPrefs.getString(KEY_USER_ID, null)
    }
    
    fun isLoggedIn(): Boolean {
        return encryptedPrefs.getBoolean(KEY_IS_LOGGED_IN, false) && 
               getAuthToken() != null
    }
    
    fun getLoginTimestamp(): Long {
        return encryptedPrefs.getLong(KEY_LOGIN_TIMESTAMP, 0L)
    }
    
    fun isTokenExpired(expirationDurationMillis: Long = TOKEN_EXPIRATION_DURATION): Boolean {
        val loginTime = getLoginTimestamp()
        if (loginTime == 0L) return true
        return (System.currentTimeMillis() - loginTime) > expirationDurationMillis
    }
    
    fun logout() {
        encryptedPrefs.edit().apply {
            remove(KEY_AUTH_TOKEN)
            remove(KEY_USER_ID)
            remove(KEY_IS_LOGGED_IN)
            remove(KEY_LOGIN_TIMESTAMP)
        }.apply()
    }
    
    fun clearAllData() {
        encryptedPrefs.edit().clear().apply()
    }
    
    companion object {
        private const val PREFS_NAME = "secure_auth_prefs"
        private const val KEY_AUTH_TOKEN = "auth_token"
        private const val KEY_USER_ID = "user_id"
        private const val KEY_IS_LOGGED_IN = "is_logged_in"
        private const val KEY_LOGIN_TIMESTAMP = "login_timestamp"
        private const val TOKEN_EXPIRATION_DURATION = 30L * 24 * 60 * 60 * 1000
        
        @Volatile
        private var instance: AuthenticationManager? = null
        
        fun getInstance(context: Context): AuthenticationManager {
            return instance ?: synchronized(this) {
                instance ?: AuthenticationManager(context.applicationContext).also {
                    instance = it
                }
            }
        }
    }
}